#include <vector>
#include <stack>
using namespace std;

class Solution {
public:
    vector<int> StatPortRates(vector<int>& portRates) {
        int n = portRates.size();
        vector<int> ans(n, 0);
        stack<int> st; // 单调栈，存放还没有找到更大流量速率的下标

        for (int i = 0; i < n; i++) {
            // 当前流量速率更大，说明找到了栈顶下标对应的答案
            while (!st.empty() && portRates[i] > portRates[st.top()]) {
                int idx = st.top();
                st.pop();
                ans[idx] = i - idx;
            }

            // 当前下标入栈，等待后面更大的流量速率
            st.push(i);
        }

        return ans;
    }
};
